import type { CanvasHostRenderRequest } from "./canvas-host-protocol";

export type CanvasHostRenderEntry = CanvasHostRenderRequest & {
  status: "active" | "cached";
  activeCount: number;
  revision: number;
  lastInactiveAt?: number;
};

export type CanvasHostRenderSize = {
  width?: number;
  height?: number;
  intrinsicSize?: boolean;
  revision?: number;
};

export type CanvasHostRuntimeStatePayload = {
  renders: Array<{
    renderId: string;
    importPath: string;
    importName: string;
    props?: Record<string, unknown>;
    width?: number;
    height?: number;
    intrinsicSize?: boolean;
    status: "active" | "cached";
  }>;
  maxCached: number;
};

const propsMatch = (
  a: Record<string, unknown> | undefined,
  b: Record<string, unknown> | undefined,
): boolean => JSON.stringify(a ?? {}) === JSON.stringify(b ?? {});

export function renderRequestMatchesEntry(
  entry: CanvasHostRenderEntry | undefined,
  request: CanvasHostRenderRequest,
): boolean {
  return (
    entry?.importPath === request.importPath &&
    entry.importName === request.importName &&
    entry.width === request.width &&
    entry.height === request.height &&
    entry.intrinsicSize === request.intrinsicSize &&
    propsMatch(entry.props, request.props)
  );
}

export function acquireRender(
  entries: ReadonlyMap<string, CanvasHostRenderEntry>,
  request: CanvasHostRenderRequest,
): Map<string, CanvasHostRenderEntry> {
  const next = new Map(entries);
  const current = next.get(request.renderId);
  const changed = !renderRequestMatchesEntry(current, request);
  next.set(request.renderId, {
    ...request,
    status: "active",
    activeCount: (current?.activeCount ?? 0) + 1,
    revision: changed ? (current?.revision ?? 0) + 1 : (current?.revision ?? 1),
  });
  return next;
}

export function releaseRender(
  entries: ReadonlyMap<string, CanvasHostRenderEntry>,
  renderId: string,
  maxCached: number,
  now = Date.now(),
): Map<string, CanvasHostRenderEntry> {
  const current = entries.get(renderId);
  if (!current) return new Map(entries);

  const next = new Map(entries);
  const activeCount = Math.max(0, current.activeCount - 1);
  if (activeCount > 0) {
    next.set(renderId, { ...current, activeCount, status: "active" });
    return next;
  }

  next.set(renderId, {
    ...current,
    activeCount: 0,
    status: "cached",
    lastInactiveAt: now,
  });
  return evictCachedRenders(next, maxCached);
}

export function evictCachedRenders(
  entries: ReadonlyMap<string, CanvasHostRenderEntry>,
  maxCached: number,
): Map<string, CanvasHostRenderEntry> {
  const next = new Map(entries);
  const cached = [...next.values()]
    .filter((entry) => entry.status === "cached")
    .sort((a, b) => (a.lastInactiveAt ?? 0) - (b.lastInactiveAt ?? 0));
  for (const entry of cached.slice(0, Math.max(0, cached.length - maxCached))) {
    next.delete(entry.renderId);
  }
  return next;
}

export function buildRenderStatePayload(
  entries: ReadonlyMap<string, CanvasHostRenderEntry>,
  maxCached: number,
): CanvasHostRuntimeStatePayload {
  return {
    renders: [...entries.values()].map(
      ({
        activeCount: _activeCount,
        lastInactiveAt: _lastInactiveAt,
        revision: _revision,
        ...entry
      }) => entry,
    ),
    maxCached,
  };
}

export function buildRenderStatusMap(
  entries: ReadonlyMap<string, CanvasHostRenderEntry>,
): ReadonlyMap<string, "active" | "cached"> {
  return new Map([...entries].map(([id, entry]) => [id, entry.status]));
}

export function buildRenderSizeMap(
  entries: ReadonlyMap<string, CanvasHostRenderEntry>,
): ReadonlyMap<string, CanvasHostRenderSize> {
  return new Map(
    [...entries].map(([id, entry]) => [
      id,
      {
        width: entry.width,
        height: entry.height,
        intrinsicSize: entry.intrinsicSize,
        revision: entry.revision,
      },
    ]),
  );
}
