import {
  Children,
  cloneElement,
  createContext,
  isValidElement,
  useContext,
  useMemo,
  type ReactNode,
} from "react";

import { normalizeId } from "./ids";

type CanvasIdentity = {
  path: string;
};

const CanvasIdentityContext = createContext<CanvasIdentity | null>(null);

export function getCanvasStoryboardRenderId(
  canvasPath: string,
  storyboardId: string,
): string {
  return `canvas:${encodeURIComponent(
    normalizeId(canvasPath, "Canvas path"),
  )}#storyboard:${encodeURIComponent(
    normalizeId(storyboardId, "Storyboard id"),
  )}`;
}

export function useCanvasIdentity(): CanvasIdentity | null {
  return useContext(CanvasIdentityContext);
}

export function useCanvasStoryboardRenderId(storyboardId: string): string {
  const canvas = useCanvasIdentity();
  const normalizedId = normalizeId(storyboardId, "Storyboard id");
  return canvas
    ? getCanvasStoryboardRenderId(canvas.path, normalizedId)
    : normalizedId;
}

export function Canvas({
  children,
  name,
  path,
  backgroundColor,
  defaultViewport,
}: {
  children?: ReactNode;
  name: string;
  path?: string;
  backgroundColor?: string;
  defaultViewport?: { x: number; y: number; zoom: number };
}) {
  const contextIdentity = useCanvasIdentity();
  const canvasName = normalizeId(name, "Canvas name");
  const canvasPath =
    path === undefined
      ? contextIdentity?.path
      : normalizeId(path, "Canvas path");

  if (!canvasPath) {
    throw new Error(
      '<Canvas> must be rendered inside <CanvasContext path="..."> or receive a path prop.',
    );
  }

  const identity = useMemo(() => ({ path: canvasPath }), [canvasPath]);

  // Key each storyboard child by its declared id so React reconciles slots
  // by STORYBOARD IDENTITY rather than child position. Canvas files declare
  // storyboards as static JSX siblings (no keys), and positional
  // reconciliation reuses one storyboard's slot DOM node for another when
  // an edit inserts or removes a sibling above it — but slot DOM identity
  // is load-bearing: capture watchers, portal tracking, and the pool's
  // render-content wrappers all anchor to the slot node, and a reused node
  // silently starts feeding one storyboard's pipeline with another's
  // render.
  const keyedChildren = useMemo(
    () =>
      Children.map(children, (child) => {
        if (!isValidElement(child)) return child;
        if (child.key != null) return child;
        const id = (child.props as { id?: unknown }).id;
        if (typeof id !== "string" || id.length === 0) return child;
        return cloneElement(child, { key: `storyboard:${id}` });
      }),
    [children],
  );

  return (
    <CanvasIdentityContext.Provider value={identity}>
      <div
        data-tempo-canvas={canvasName}
        data-tempo-canvas-path={canvasPath}
        data-tempo-canvas-background={backgroundColor}
        data-tempo-canvas-viewport={
          defaultViewport ? JSON.stringify(defaultViewport) : undefined
        }
      >
        {keyedChildren}
      </div>
    </CanvasIdentityContext.Provider>
  );
}

export function CanvasContext({
  children,
  path,
}: {
  children?: ReactNode;
  path: string;
}) {
  const canvasPath = normalizeId(path, "Canvas path");
  const identity = useMemo(() => ({ path: canvasPath }), [canvasPath]);
  return (
    <CanvasIdentityContext.Provider value={identity}>
      {children}
    </CanvasIdentityContext.Provider>
  );
}
