import {
  getCanvasHostRuntime,
  type CanvasHostCaptureResult,
  type CanvasHostRuntime,
  type CanvasHostWatch,
} from "./canvas-host-runtime";
import { getStoryboardPortalSelectors } from "./portal-tracking";

const escapeRenderId = (renderId: string): string =>
  renderId.replace(/\\/g, "\\\\").replace(/"/g, '\\"');

export const buildRenderSelector = (renderId: string): string =>
  `[data-render-id="${escapeRenderId(renderId)}"]`;

export const buildRenderContentSelector = (renderId: string): string =>
  `[data-render-content="${escapeRenderId(renderId)}"]`;

export const buildRenderContentFiberSelector = (renderId: string): string =>
  `${buildRenderContentSelector(renderId)} > :not([data-tempo-hide-fiber="true"])`;

type DomCaptureLike = {
  dom?: {
    selector?: string;
    attributes?: Record<string, unknown>;
    rootAttributes?: Record<string, unknown>;
  };
};

export function stripRenderContentWrapperAttributes<T>(
  capture: T,
  renderId: string,
): T {
  if (!capture || typeof capture !== "object") return capture;
  const dom = (capture as DomCaptureLike).dom;
  if (!dom) return capture;

  const shouldStripAttributes =
    dom.selector === "" && dom.attributes?.["data-render-content"] === renderId;
  const shouldStripRootAttributes =
    dom.rootAttributes?.["data-render-content"] === renderId;

  if (!shouldStripAttributes && !shouldStripRootAttributes) return capture;

  return {
    ...capture,
    dom: {
      ...dom,
      attributes: shouldStripAttributes ? undefined : dom.attributes,
      rootAttributes: shouldStripRootAttributes
        ? undefined
        : dom.rootAttributes,
    },
  };
}

export function stripRenderContentWrapperFromCombinedCapture<T>(
  capture: T,
  renderId: string,
): T {
  if (!capture || typeof capture !== "object" || !("html" in capture)) {
    return capture;
  }
  const html = (capture as { html?: unknown }).html;
  if (!html) return capture;
  return {
    ...capture,
    html: stripRenderContentWrapperAttributes(html, renderId),
  };
}

export function captureStoryboardImage(
  renderId: string,
  options?: Parameters<CanvasHostRuntime["captureSelector"]>[1],
): Promise<CanvasHostCaptureResult | null> {
  const portalSelectors = [
    ...(options?.portalSelectors ?? []),
    ...getStoryboardPortalSelectors(renderId),
  ];

  return getCanvasHostRuntime().captureSelector(
    buildRenderSelector(renderId),
    portalSelectors.length > 0
      ? { ...options, portalSelectors: [...new Set(portalSelectors)] }
      : options,
  );
}

export async function captureStoryboardHtml(
  renderId: string,
  options?: { timeout?: number },
): Promise<unknown | null> {
  const capture = await getCanvasHostRuntime().captureHtml?.({
    selector: buildRenderContentSelector(renderId),
    timeout: options?.timeout,
  });
  return capture
    ? stripRenderContentWrapperAttributes(capture, renderId)
    : null;
}

export function captureStoryboardStaticHtml(
  renderId: string,
  options?: { timeout?: number },
): Promise<unknown | null> {
  return (
    getCanvasHostRuntime().captureStaticHtml?.({
      selector: buildRenderContentSelector(renderId),
      timeout: options?.timeout,
    }) ?? Promise.resolve(null)
  );
}

export async function captureStoryboardCombined(
  renderId: string,
  options?: {
    fiberSelector?: string;
    fiberTags?: unknown[];
    timeout?: number;
  },
): Promise<unknown | null> {
  const capture = await getCanvasHostRuntime().captureCombined?.({
    selector: buildRenderContentSelector(renderId),
    fiberSelector: options?.fiberSelector ?? buildRenderContentFiberSelector(renderId),
    fiberTags: options?.fiberTags,
    timeout: options?.timeout,
  });
  return capture
    ? stripRenderContentWrapperFromCombinedCapture(capture, renderId)
    : null;
}

export function watchStoryboardHtml(
  renderId: string,
  options: {
    onUpdate(capture: unknown): void;
    onError?(error: Error): void;
    debounceDelay?: number;
    maxWait?: number;
    timeout?: number;
  },
): Promise<CanvasHostWatch> {
  const runtime = getCanvasHostRuntime();
  if (!runtime.watchHtml) {
    return Promise.reject(new Error("watchHtml is not available."));
  }
  return runtime.watchHtml({
    selector: buildRenderContentSelector(renderId),
    onUpdate(capture) {
      options.onUpdate(stripRenderContentWrapperAttributes(capture, renderId));
    },
    onError: options.onError,
    debounceDelay: options.debounceDelay,
    maxWait: options.maxWait,
    timeout: options.timeout,
  });
}

export function watchStoryboardCombined(
  renderId: string,
  options: {
    onUpdate(capture: unknown): void;
    onError?(error: Error): void;
    fiberSelector?: string;
    fiberTags?: unknown[];
    debounceDelay?: number;
    maxWait?: number;
    timeout?: number;
    knownSourceVersion?: unknown;
  },
): Promise<CanvasHostWatch> {
  const runtime = getCanvasHostRuntime();
  if (!runtime.watchCombined) {
    return Promise.reject(new Error("watchCombined is not available."));
  }
  return runtime.watchCombined({
    selector: buildRenderContentSelector(renderId),
    fiberSelector:
      options.fiberSelector ?? buildRenderContentFiberSelector(renderId),
    fiberTags: options.fiberTags,
    onUpdate(capture) {
      options.onUpdate(
        stripRenderContentWrapperFromCombinedCapture(capture, renderId),
      );
    },
    onError: options.onError,
    debounceDelay: options.debounceDelay,
    maxWait: options.maxWait,
    timeout: options.timeout,
    knownSourceVersion: options.knownSourceVersion,
  });
}
