export type CanvasHostCaptureResult = {
  img: { src: string; width: number; height: number };
  timing?: Record<string, number>;
};

export type CanvasHostWatch = {
  stop(): void | Promise<void>;
  pause?(): void;
  resume?(): void;
  setPaused?(paused: boolean): void;
};

export type CanvasHostRuntime = {
  captureSelector(
    selector: string,
    options?: {
      overlaySelector?: string;
      format?: "jpeg" | "png";
      quality?: number;
      scale?: number;
      outputPath?: string;
      forceRefresh?: boolean;
      portalSelectors?: string[];
    },
  ): Promise<CanvasHostCaptureResult | null>;
  captureHtml?(options?: {
    selector?: string;
    timeout?: number;
  }): Promise<unknown | null>;
  captureStaticHtml?(options?: {
    selector?: string;
    timeout?: number;
  }): Promise<unknown | null>;
  captureCombined?(options?: {
    selector?: string;
    fiberSelector?: string;
    fiberTags?: unknown[];
    timeout?: number;
  }): Promise<unknown | null>;
  watchHtml?(options: {
    selector?: string;
    onUpdate(capture: unknown): void;
    onError?(error: Error): void;
    debounceDelay?: number;
    maxWait?: number;
    timeout?: number;
  }): Promise<CanvasHostWatch>;
  watchCombined?(options: {
    selector?: string;
    fiberSelector?: string;
    onUpdate(capture: unknown): void;
    onError?(error: Error): void;
    debounceDelay?: number;
    maxWait?: number;
    timeout?: number;
    fiberTags?: unknown[];
    knownSourceVersion?: unknown;
  }): Promise<CanvasHostWatch>;
};

declare global {
  interface Window {
    __tempoCanvasHostRuntime?: CanvasHostRuntime;
  }
}

export function getCanvasHostRuntime(): CanvasHostRuntime {
  const runtime = window.__tempoCanvasHostRuntime;
  if (!runtime) {
    throw new Error("window.__tempoCanvasHostRuntime is not installed.");
  }
  return runtime;
}

export function getOptionalCanvasHostRuntime(): CanvasHostRuntime | undefined {
  return typeof window === "undefined"
    ? undefined
    : window.__tempoCanvasHostRuntime;
}
