import {
  useMemo,
  type ReactNode,
} from "react";

import { getCanvasStoryboardRenderId } from "./canvas";
import { normalizeId } from "./ids";
import { CanvasHostContext } from "./runtime-context";
import type { CanvasHostRuntimeSize } from "./runtime-context";
import { useCanvasHostPostMessage } from "./use-canvas-host-postmessage";

type DirectUrlRender = {
  renderId: string;
  size?: CanvasHostRuntimeSize;
};

function readDirectUrlDimension(value: string): number | string {
  const match = value.trim().match(/^([0-9]*\.?[0-9]+)(px|vw|vh)?$/);
  if (!match) {
    throw new Error(
      "Direct URL dimensions must be positive finite numbers, optionally with px, vw, or vh units",
    );
  }
  const numberPart = match[1] ?? "";
  const unit = match[2] ?? "";
  const numberValue = Number(numberPart);
  if (!numberPart || !Number.isFinite(numberValue) || numberValue <= 0) {
    throw new Error(
      "Direct URL dimensions must be positive finite numbers, optionally with px, vw, or vh units",
    );
  }
  return unit && unit !== "px" ? `${numberValue}${unit}` : numberValue;
}

function readDirectUrlSize(params: URLSearchParams): CanvasHostRuntimeSize | undefined {
  const width = params.get("width")?.trim();
  const height = params.get("height")?.trim();
  if (!width && !height) return undefined;
  if (!width || !height) {
    throw new Error("Direct URL width and height must be provided together");
  }
  return {
    width: readDirectUrlDimension(width),
    height: readDirectUrlDimension(height),
    revision: 1,
  };
}

function readDirectUrlRender(): DirectUrlRender | null {
  if (typeof window === "undefined") return null;
  const params = new URLSearchParams(window.location.search);
  const canvasPath =
    params.get("canvasPath")?.trim() ??
    params.get("pageFile")?.trim() ??
    params.get("importPath")?.trim() ??
    "";
  const storyboardId =
    params.get("storyboardId")?.trim() ??
    params.get("exportName")?.trim() ??
    params.get("importName")?.trim() ??
    "";
  if (!canvasPath || !storyboardId) return null;
  return {
    renderId: getCanvasStoryboardRenderId(canvasPath, storyboardId),
    size: readDirectUrlSize(params),
  };
}

export function CanvasHost({
  children,
  activeStoryboardIds,
  isStoryboardActive,
}: {
  children?: ReactNode;
  activeStoryboardIds?: ReadonlySet<string> | readonly string[];
  isStoryboardActive?: (storyboardId: string) => boolean;
}) {
  const {
    renderStatusById,
    renderSizeById,
    markStoryboardRendered,
    reportStoryboardError,
    clearStoryboardError,
  } = useCanvasHostPostMessage();
  const directUrlSearch =
    typeof window === "undefined" ? "" : window.location.search;
  const directUrlRender = useMemo(readDirectUrlRender, [directUrlSearch]);
  const propActiveIds = useMemo(
    () => new Set(activeStoryboardIds ?? []),
    [activeStoryboardIds],
  );

  const runtime = useMemo(
    () => ({
      getStoryboardStatus(storyboardId: string) {
        const normalizedId = normalizeId(storyboardId, "Storyboard id");
        if (
          propActiveIds.has(normalizedId) ||
          directUrlRender?.renderId === normalizedId ||
          (isStoryboardActive ? isStoryboardActive(normalizedId) : false)
        ) {
          return "active" as const;
        }
        return renderStatusById.get(normalizedId) ?? "unmounted";
      },
      getStoryboardSize(storyboardId: string) {
        const normalizedId = normalizeId(storyboardId, "Storyboard id");
        if (directUrlRender?.renderId === normalizedId) {
          return directUrlRender.size;
        }
        return renderSizeById.get(normalizedId);
      },
      getStoryboardPlacement(storyboardId: string) {
        const normalizedId = normalizeId(storyboardId, "Storyboard id");
        return directUrlRender?.renderId === normalizedId
          ? { left: 0, top: 0 }
          : undefined;
      },
      markStoryboardRendered,
      reportStoryboardError,
      clearStoryboardError,
    }),
    [
      clearStoryboardError,
      directUrlRender,
      isStoryboardActive,
      markStoryboardRendered,
      propActiveIds,
      reportStoryboardError,
      renderSizeById,
      renderStatusById,
    ],
  );

  return (
    <CanvasHostContext.Provider value={runtime}>
      {children}
    </CanvasHostContext.Provider>
  );
}
