export type CanvasHostProblemSourceKind =
  | "page-error"
  | "unhandled-rejection"
  | "resource-load"
  | "vite-overlay"
  | "vite-hmr-error"
  | "console-vite-error"
  | "vite-ws-disconnect"
  | "did-fail-load"
  | "render-process-gone"
  | "render-process-oom"
  | "bridge-disconnect"
  | "capture-error"
  | "watch-error"
  | "timeout"
  | "runtime-bootstrap"
  | "render-error-boundary"
  | "worker-error";

export type CanvasHostRuntimeProblem = {
  sourceKind: CanvasHostProblemSourceKind;
  message: string;
  stack?: string;
  componentStack?: string;
  filename?: string;
  line?: number;
  column?: number;
  frameUrl?: string;
  frameId?: number;
  timestamp: number;
};

export type CanvasHostProblemSnapshot = {
  hostProblem?: CanvasHostRuntimeProblem;
  componentProblems: Array<{
    renderId: string;
    problem: CanvasHostRuntimeProblem;
  }>;
  // Failures scoped to a whole canvas rather than a single storyboard. A canvas
  // whose module fails to load never registers any storyboard, so it has no
  // renderId to key a component problem on; but reporting host-wide would
  // false-flag the sibling canvases sharing this host. Keying by canvas path
  // lets the renderer surface the error on exactly that canvas's storyboards.
  canvasProblems: Array<{
    canvasPath: string;
    problem: CanvasHostRuntimeProblem;
  }>;
};

export type CanvasHostCurrentFrameProblemSnapshot = {
  currentHostFailure?: CanvasHostRuntimeProblem;
  currentRenderFailures: Array<{
    renderId: string | null;
    failure: CanvasHostRuntimeProblem;
  }>;
  // See CanvasHostProblemSnapshot.canvasProblems — the pull-probe mirror of the
  // canvas-scoped failure lane.
  currentCanvasFailures: Array<{
    canvasPath: string;
    failure: CanvasHostRuntimeProblem;
  }>;
  observedAt: number;
};

export class CanvasHostProblemTracker {
  private hostProblem: CanvasHostRuntimeProblem | undefined;
  private hostProblemHmrGeneration = 0;
  private componentProblems = new Map<string, CanvasHostRuntimeProblem>();
  private componentProblemHmrGenerations = new Map<string, number>();
  private canvasProblems = new Map<string, CanvasHostRuntimeProblem>();
  private watchers = new Set<() => void>();
  private hostProblemClearedWatchers = new Set<
    (problem: CanvasHostRuntimeProblem) => void
  >();
  private hmrGeneration = 0;

  snapshot(): CanvasHostProblemSnapshot {
    const currentViteOverlay = readCurrentViteOverlay();
    const hostProblem =
      currentViteOverlay ??
      (this.hostProblem?.sourceKind === "vite-overlay"
        ? undefined
        : this.hostProblem);
    return {
      hostProblem,
      componentProblems: [...this.componentProblems].map(
        ([renderId, problem]) => ({ renderId, problem }),
      ),
      canvasProblems: [...this.canvasProblems].map(([canvasPath, problem]) => ({
        canvasPath,
        problem,
      })),
    };
  }

  watch(callback: () => void): () => void {
    this.watchers.add(callback);
    return () => {
      this.watchers.delete(callback);
    };
  }

  watchHostProblemCleared(
    callback: (problem: CanvasHostRuntimeProblem) => void,
  ): () => void {
    this.hostProblemClearedWatchers.add(callback);
    return () => {
      this.hostProblemClearedWatchers.delete(callback);
    };
  }

  reportHostProblem(
    sourceKind: CanvasHostProblemSourceKind,
    error: unknown,
    details: Partial<CanvasHostRuntimeProblem> = {},
  ): void {
    this.hostProblem = createProblem(sourceKind, error, details);
    this.hostProblemHmrGeneration = this.hmrGeneration;
    this.publish();
  }

  reportProblemNearRender(
    sourceKind: CanvasHostProblemSourceKind,
    error: unknown,
    details: Partial<CanvasHostRuntimeProblem> = {},
  ): void {
    const problem = createProblem(sourceKind, error, details);
    const renderId = findRenderIdForProblem(problem);
    if (renderId) {
      this.componentProblems.set(renderId, problem);
      this.componentProblemHmrGenerations.set(renderId, this.hmrGeneration);
    } else {
      this.hostProblem = problem;
      this.hostProblemHmrGeneration = this.hmrGeneration;
    }
    this.publish();
  }

  // A whole-canvas failure (its module failed to import, so none of its
  // storyboards ever registered). Keyed by canvas path, not renderId — the
  // renderer scopes it to that canvas's storyboards.
  reportCanvasProblem(
    canvasPath: string,
    sourceKind: CanvasHostProblemSourceKind,
    error: unknown,
    details: Partial<CanvasHostRuntimeProblem> = {},
  ): void {
    this.canvasProblems.set(canvasPath, createProblem(sourceKind, error, details));
    this.publish();
  }

  clearCanvasProblem(canvasPath: string): void {
    if (!this.canvasProblems.delete(canvasPath)) return;
    this.publish();
  }

  clearHostProblem(sourceKinds?: readonly CanvasHostProblemSourceKind[]): void {
    if (!this.hostProblem) return;
    if (sourceKinds && !sourceKinds.includes(this.hostProblem.sourceKind)) return;
    const clearedProblem = this.hostProblem;
    this.hostProblem = undefined;
    this.hostProblemHmrGeneration = 0;
    this.publish();
    this.publishHostProblemCleared(clearedProblem);
  }

  reportComponentProblem(
    renderId: string,
    sourceKind: CanvasHostProblemSourceKind,
    error: unknown,
    details: Partial<CanvasHostRuntimeProblem> = {},
  ): void {
    this.componentProblems.set(
      renderId,
      createProblem(sourceKind, error, details),
    );
    this.componentProblemHmrGenerations.set(renderId, this.hmrGeneration);
    this.publish();
  }

  clearComponentProblem(
    renderId: string,
    sourceKinds?: readonly CanvasHostProblemSourceKind[],
  ): void {
    const problem = this.componentProblems.get(renderId);
    if (!problem) return;
    if (sourceKinds && !sourceKinds.includes(problem.sourceKind)) return;
    this.componentProblems.delete(renderId);
    this.componentProblemHmrGenerations.delete(renderId);
    this.publish();
  }

  hasComponentProblem(renderId: string): boolean {
    return this.componentProblems.has(renderId);
  }

  clearRecoveredComponentProblemsAfterRender(renderId: string): void {
    let changed = false;
    const problem = this.componentProblems.get(renderId);
    if (
      problem &&
      problem.sourceKind !== "render-error-boundary" &&
      this.hmrGeneration >
        (this.componentProblemHmrGenerations.get(renderId) ?? this.hmrGeneration)
    ) {
      this.componentProblems.delete(renderId);
      this.componentProblemHmrGenerations.delete(renderId);
      changed = true;
    }
    if (this.clearRecoveredHostProblemAfterRender(renderId)) changed = true;
    if (changed) this.publish();
  }

  noteHmrUpdateStarted(): void {
    this.hmrGeneration += 1;
  }

  dispose(): void {
    this.watchers.clear();
    this.hostProblemClearedWatchers.clear();
  }

  inspectCurrentProblems(options: { renderId?: string | null } = {}) {
    const renderIdFilter = options.renderId ?? undefined;
    const currentRenderFailures: CanvasHostCurrentFrameProblemSnapshot["currentRenderFailures"] =
      [];
    for (const [renderId, failure] of this.componentProblems) {
      if (renderIdFilter != null && renderId !== renderIdFilter) continue;
      currentRenderFailures.push({ renderId, failure });
    }

    const currentHostFailure = readCurrentViteOverlay() ?? this.hostProblem;
    return {
      ...(currentHostFailure ? { currentHostFailure } : {}),
      currentRenderFailures,
      currentCanvasFailures: [...this.canvasProblems].map(
        ([canvasPath, failure]) => ({ canvasPath, failure }),
      ),
      observedAt: Date.now(),
    };
  }

  private publish(): void {
    for (const watcher of this.watchers) {
      watcher();
    }
  }

  private publishHostProblemCleared(problem: CanvasHostRuntimeProblem): void {
    for (const watcher of this.hostProblemClearedWatchers) {
      watcher(problem);
    }
  }

  private clearRecoveredHostProblemAfterRender(renderId: string): boolean {
    if (
      !this.hostProblem ||
      !renderRecoveredHostProblemSourceKinds.includes(this.hostProblem.sourceKind)
    ) {
      return false;
    }
    if (this.hmrGeneration <= this.hostProblemHmrGeneration) return false;
    if (
      this.hostProblem.sourceKind === "vite-hmr-error" &&
      findRenderIdForProblem(this.hostProblem) !== renderId
    ) {
      return false;
    }
    const clearedProblem = this.hostProblem;
    this.hostProblem = undefined;
    this.hostProblemHmrGeneration = 0;
    this.publishHostProblemCleared(clearedProblem);
    return true;
  }
}

export function createCanvasHostProblemTracker(): CanvasHostProblemTracker {
  return new CanvasHostProblemTracker();
}

export function installCanvasHostRuntimeProblemTracking(
  tracker: CanvasHostProblemTracker,
): () => void {
  if (typeof window === "undefined") return () => {};

  const cleanupHostCapture = installHostProblemCapture(tracker);
  const cleanupCanvasImportCapture = installCanvasImportProblemCapture(tracker);
  const cleanupViteCapture = installViteProblemCapture(tracker);
  const cleanupInspector = installCurrentProblemInspector(tracker);

  return () => {
    cleanupHostCapture();
    cleanupCanvasImportCapture();
    cleanupViteCapture();
    cleanupInspector();
    tracker.dispose();
  };
}

// The generated .tempo/tempo-host.tsx wraps each demand-registered canvas in a
// CanvasImportBoundary that, on a module-load failure, renders null (isolating
// the broken canvas) AND dispatches a `tempo:canvas-import-error` window
// CustomEvent tagged with the canvas path. That boundary has no import surface
// beyond React, so the event is its only way to reach this tracker. Convert it
// into a canvas-scoped problem so the renderer can surface it on that canvas's
// storyboards instead of leaving them spinning. Keep the event name in sync
// with buildTempoHostWrapper in tempo-devserver.ts.
type CanvasImportErrorDetail = {
  canvasPath?: unknown;
  message?: unknown;
  stack?: unknown;
};

function installCanvasImportProblemCapture(
  tracker: CanvasHostProblemTracker,
): () => void {
  const onCanvasImportError = (event: Event): void => {
    const detail = (event as CustomEvent<CanvasImportErrorDetail>).detail;
    if (typeof detail !== "object" || detail === null) return;
    const canvasPath =
      typeof detail.canvasPath === "string" ? detail.canvasPath : "";
    if (!canvasPath) return;
    const message =
      typeof detail.message === "string" && detail.message
        ? detail.message
        : "Canvas module failed to load";
    tracker.reportCanvasProblem(canvasPath, "runtime-bootstrap", message, {
      stack: typeof detail.stack === "string" ? detail.stack : undefined,
      filename: canvasPath,
    });
  };
  window.addEventListener("tempo:canvas-import-error", onCanvasImportError);
  return () => {
    window.removeEventListener("tempo:canvas-import-error", onCanvasImportError);
  };
}

const renderRecoveredHostProblemSourceKinds: readonly CanvasHostProblemSourceKind[] =
  ["page-error", "unhandled-rejection", "console-vite-error", "vite-hmr-error"];

function createProblem(
  sourceKind: CanvasHostProblemSourceKind,
  error: unknown,
  details: Partial<CanvasHostRuntimeProblem> = {},
): CanvasHostRuntimeProblem {
  return {
    sourceKind,
    message: error instanceof Error ? error.message : String(error),
    stack: error instanceof Error ? error.stack : undefined,
    frameUrl:
      typeof window === "undefined" ? undefined : window.location.href,
    timestamp: Date.now(),
    ...details,
  };
}

function findRenderIdForProblem(
  problem: CanvasHostRuntimeProblem,
): string | undefined {
  if (typeof document === "undefined") return undefined;
  const haystack = [
    problem.message,
    problem.stack,
    problem.componentStack,
    problem.filename,
  ]
    .filter(Boolean)
    .join("\n");
  if (!haystack) return undefined;

  for (const slot of document.querySelectorAll("[data-render-id]")) {
    const renderId = slot.getAttribute("data-render-id");
    if (!renderId) continue;
    const sourceFiles = getObservedSourceFiles(slot);
    if (
      sourceFiles.some((sourceFile) => problemTextMentionsSource(haystack, sourceFile))
    ) {
      return renderId;
    }
  }
  return undefined;
}

const sourceAnnotationSelector =
  "[data-tempo-source-file], [data-tempo-source-loc], [data-tempo-filepath], [data-tempo-html-filepath]";

function getObservedSourceFiles(slot: Element): string[] {
  const sourceFiles = new Set<string>();
  for (const element of slot.querySelectorAll(sourceAnnotationSelector)) {
    for (const attribute of [
      "data-tempo-source-file",
      "data-tempo-filepath",
      "data-tempo-html-filepath",
    ]) {
      const value = element.getAttribute(attribute);
      if (value) sourceFiles.add(value);
    }
    const sourceLoc = element.getAttribute("data-tempo-source-loc");
    const sourceFile = sourceLoc?.split(":")[0];
    if (sourceFile) sourceFiles.add(sourceFile);
  }
  return [...sourceFiles];
}

function problemTextMentionsSource(text: string, sourceFile: string): boolean {
  const normalizedSource = sourceFile.replace(/\\/g, "/");
  const basename = normalizedSource.split("/").pop() ?? normalizedSource;
  return (
    text.includes(normalizedSource) || (basename !== "" && text.includes(basename))
  );
}

function installHostProblemCapture(
  tracker: CanvasHostProblemTracker,
): () => void {
  const onError = (event: ErrorEvent): void => {
    if (event.target instanceof Element) return;
    tracker.reportProblemNearRender("page-error", event.error ?? event.message, {
      filename: event.filename || undefined,
      line: typeof event.lineno === "number" ? event.lineno : undefined,
      column: typeof event.colno === "number" ? event.colno : undefined,
    });
  };
  const onUnhandledRejection = (event: PromiseRejectionEvent): void => {
    tracker.reportProblemNearRender("unhandled-rejection", event.reason);
  };

  const resourceTags = new Set([
    "IMG",
    "SCRIPT",
    "LINK",
    "AUDIO",
    "VIDEO",
    "SOURCE",
  ]);
  const onResourceError = (event: Event): void => {
    const target = event.target;
    if (!(target instanceof Element) || !resourceTags.has(target.tagName)) {
      return;
    }
    const url = target.getAttribute("src") || target.getAttribute("href") || "";
    const message =
      "Failed to load " +
      target.tagName.toLowerCase() +
      (url ? ": " + url : "");
    const renderId = target
      .closest("[data-render-id]")
      ?.getAttribute("data-render-id");
    if (renderId) {
      tracker.reportComponentProblem(renderId, "resource-load", message);
    } else {
      tracker.reportHostProblem("resource-load", message, {
        filename: url || undefined,
      });
    }
  };

  const onFontLoadingError = (event: Event): void => {
    const faces =
      (event as Event & { fontfaces?: ReadonlyArray<{ family?: string }> })
        .fontfaces ?? [];
    const families = faces
      .map((face) => face.family)
      .filter(Boolean)
      .join(", ");
    tracker.reportHostProblem(
      "resource-load",
      "Failed to load font" + (families ? ": " + families : ""),
    );
  };
  const fontFaceSet =
    typeof document.fonts?.addEventListener === "function"
      ? document.fonts
      : undefined;

  window.addEventListener("error", onError);
  window.addEventListener("unhandledrejection", onUnhandledRejection);
  window.addEventListener("error", onResourceError, { capture: true });
  document.addEventListener("error", onResourceError, { capture: true });
  fontFaceSet?.addEventListener("loadingerror", onFontLoadingError);

  return () => {
    window.removeEventListener("error", onError);
    window.removeEventListener("unhandledrejection", onUnhandledRejection);
    window.removeEventListener("error", onResourceError, { capture: true });
    document.removeEventListener("error", onResourceError, { capture: true });
    fontFaceSet?.removeEventListener("loadingerror", onFontLoadingError);
  };
}

function installViteProblemCapture(
  tracker: CanvasHostProblemTracker,
): () => void {
  const reconcileViteOverlay = (): void => {
    const problem = readCurrentViteOverlay();
    if (problem) {
      tracker.reportHostProblem("vite-overlay", problem.message, {
        stack: problem.stack,
        filename: problem.filename,
      });
    } else {
      tracker.clearHostProblem(["vite-overlay"]);
    }
  };

  const observer = new MutationObserver(reconcileViteOverlay);
  if (document.body) {
    observer.observe(document.body, { childList: true });
    reconcileViteOverlay();
    void Promise.resolve().then(reconcileViteOverlay);
  }

  const viteHmrFailedModules = new Map<string, CanvasHostRuntimeProblem>();
  const latestViteHmrFailure = (): CanvasHostRuntimeProblem | undefined => {
    let latest: CanvasHostRuntimeProblem | undefined;
    for (const problem of viteHmrFailedModules.values()) {
      if (!latest || problem.timestamp >= latest.timestamp) latest = problem;
    }
    return latest;
  };
  const reconcileViteHmrHostProblem = (): void => {
    const latest = latestViteHmrFailure();
    if (latest) {
      tracker.reportHostProblem("vite-hmr-error", latest.message, latest);
    } else {
      tracker.clearHostProblem(["vite-hmr-error"]);
    }
  };

  const failedReloadPattern = /^Failed to reload (.+?)\. This could be due to/;
  const pathlessViteErrorKey = "__tempo:pathless-vite-error";
  let viteHmrCycleActive = false;
  let cycleFailedPaths = new Map<string, CanvasHostRuntimeProblem>();
  let lastCycleViteErrorDetail:
    | { message: string; stack?: string; filename?: string }
    | undefined;

  const onViteBeforeUpdate = (): void => {
    viteHmrCycleActive = true;
    cycleFailedPaths = new Map();
    lastCycleViteErrorDetail = undefined;
    tracker.noteHmrUpdateStarted();
  };

  const onViteAfterUpdate = (payload: unknown): void => {
    const updatedPaths = readUpdatePaths(payload);
    let shouldReconcile = false;
    if (updatedPaths.length > 0 && !cycleFailedPaths.has(pathlessViteErrorKey)) {
      shouldReconcile = viteHmrFailedModules.delete(pathlessViteErrorKey);
    }
    for (const [path, problem] of cycleFailedPaths) {
      viteHmrFailedModules.set(path, problem);
      shouldReconcile = true;
    }
    viteHmrCycleActive = false;
    cycleFailedPaths = new Map();
    if (shouldReconcile) reconcileViteHmrHostProblem();
  };

  const onViteError = (payload: unknown): void => {
    const error = readViteError(payload);
    if (!error) return;

    lastCycleViteErrorDetail = error;
    const path = error.filename ?? pathlessViteErrorKey;
    const problem = createProblem("vite-hmr-error", error.message, {
      stack: error.stack,
      filename: error.filename,
    });
    if (viteHmrCycleActive) {
      cycleFailedPaths.set(path, problem);
    } else {
      viteHmrFailedModules.set(path, problem);
    }
    reconcileViteHmrHostProblem();
  };

  let hotEventsCancelled = false;
  let subscribedHot: ViteHot | undefined;
  const subscribeHotEvents = (hot: ViteHot): void => {
    subscribedHot = hot;
    hot.on?.("vite:beforeUpdate", onViteBeforeUpdate);
    hot.on?.("vite:afterUpdate", onViteAfterUpdate);
    hot.on?.("vite:error", onViteError);
  };
  const hot = readViteHot();
  if (hot?.on) {
    subscribeHotEvents(hot);
  } else {
    void import(
      /* @vite-ignore */
      /* webpackIgnore: true */
      /* turbopackIgnore: true */
      "/@vite/client"
    )
      .then((client: unknown) => {
        const createHotContext = (
          client as {
            createHotContext?: (ownerPath: string) => ViteHot | undefined;
          }
        ).createHotContext;
        const context = createHotContext?.("/__tempo-canvas-host__");
        if (!context || hotEventsCancelled) return;
        subscribeHotEvents(context);
      })
      .catch(() => {});
  }

  const stopClearedWatch = tracker.watchHostProblemCleared((problem) => {
    if (problem.sourceKind !== "vite-hmr-error") return;
    const key = problem.filename ?? pathlessViteErrorKey;
    if (!viteHmrFailedModules.has(key)) return;
    viteHmrFailedModules.delete(key);
    void Promise.resolve().then(reconcileViteHmrHostProblem);
  });

  const originalConsoleError = console.error;
  const patchedConsoleError = (...args: unknown[]): void => {
    originalConsoleError(...args);
    const error = readViteConsoleError(args[0], args[1]);
    if (!error) return;

    const failedReload = failedReloadPattern.exec(error.message);
    if (failedReload) {
      const path = failedReload[1];
      const detail = lastCycleViteErrorDetail;
      const problem = createProblem(
        "vite-hmr-error",
        detail?.message ?? "Failed to reload " + path,
        {
          stack: detail?.stack ?? error.stack,
          filename: detail?.filename ?? path,
        },
      );
      if (detail) {
        cycleFailedPaths.set(path, problem);
        viteHmrFailedModules.set(path, problem);
        reconcileViteHmrHostProblem();
      } else {
        void verifyModuleStillExists(path).then((exists) => {
          if (exists) viteHmrFailedModules.set(path, problem);
          else viteHmrFailedModules.delete(path);
          reconcileViteHmrHostProblem();
        });
      }
      return;
    }

    if (viteHmrCycleActive) {
      lastCycleViteErrorDetail = error;
      return;
    }

    tracker.reportProblemNearRender("console-vite-error", error.message, {
      stack: error.stack,
      filename: error.filename,
    });
  };
  console.error = patchedConsoleError;

  return () => {
    observer.disconnect();
    stopClearedWatch();
    hotEventsCancelled = true;
    subscribedHot?.off?.("vite:beforeUpdate", onViteBeforeUpdate);
    subscribedHot?.off?.("vite:afterUpdate", onViteAfterUpdate);
    subscribedHot?.off?.("vite:error", onViteError);
    if (console.error === patchedConsoleError) {
      console.error = originalConsoleError;
    }
  };
}

function installCurrentProblemInspector(
  tracker: CanvasHostProblemTracker,
): () => void {
  const maybeWindow = window as unknown as {
    __tempoErrorTrackingInspectCurrentProblems?: (options?: {
      renderId?: string | null;
    }) => CanvasHostCurrentFrameProblemSnapshot | null;
  };
  const previous = maybeWindow.__tempoErrorTrackingInspectCurrentProblems;
  const inspect = (options: { renderId?: string | null } = {}) =>
    mergeCurrentProblemSnapshots(
      tracker.inspectCurrentProblems(options),
      previous?.(options) ?? null,
    );
  maybeWindow.__tempoErrorTrackingInspectCurrentProblems = inspect;
  return () => {
    if (maybeWindow.__tempoErrorTrackingInspectCurrentProblems === inspect) {
      maybeWindow.__tempoErrorTrackingInspectCurrentProblems = previous;
    }
  };
}

type ViteHot = {
  on?: (name: string, callback: (payload: unknown) => void) => void;
  off?: (name: string, callback: (payload: unknown) => void) => void;
};

function readViteHot(): ViteHot | undefined {
  const explicitHot = (window as unknown as { __tempoCanvasHostViteHot?: ViteHot })
    .__tempoCanvasHostViteHot;
  if (explicitHot) return explicitHot;
  try {
    // eslint-disable-next-line no-eval
    return eval("import.meta && import.meta.hot") as ViteHot | undefined;
  } catch {
    return undefined;
  }
}

function readCurrentViteOverlay(): CanvasHostRuntimeProblem | undefined {
  if (typeof document === "undefined") return undefined;
  const overlay = document.querySelector("vite-error-overlay");
  if (!overlay) return undefined;
  const { message, stack, filename } = readViteOverlayContent(overlay);
  return createProblem("vite-overlay", message, { stack, filename });
}

function readViteOverlayContent(overlay: Element): {
  message: string;
  stack?: string;
  filename?: string;
} {
  const root = overlay.shadowRoot ?? overlay;
  const text = (selector: string): string | undefined => {
    const value = root.querySelector(selector)?.textContent?.trim();
    return value ? value : undefined;
  };
  const message =
    text(".message-body") ??
    text(".message") ??
    overlay.textContent?.trim() ??
    "Unknown Vite error";
  const stack = [text(".stack"), text(".plugin"), text(".frame")]
    .filter(Boolean)
    .join("\n");
  return {
    message,
    stack: stack || undefined,
    filename: text(".file"),
  };
}

function readViteError(
  value: unknown,
): { message: string; stack?: string; filename?: string } | undefined {
  if (value instanceof Error) {
    return {
      message: value.message,
      stack: value.stack,
      filename:
        typeof (value as Error & { id?: unknown }).id === "string"
          ? (value as Error & { id: string }).id
          : undefined,
    };
  }
  if (typeof value === "string") return { message: value };
  if (typeof value !== "object" || value === null) return undefined;

  const record = value as Record<string, unknown>;
  const nested =
    typeof record.err === "object" && record.err !== null
      ? (record.err as Record<string, unknown>)
      : record;
  const message =
    typeof nested.message === "string"
      ? nested.message
      : typeof record.message === "string"
        ? record.message
        : undefined;
  if (!message) return undefined;

  return {
    message,
    stack:
      typeof nested.stack === "string"
        ? nested.stack
        : typeof record.stack === "string"
          ? record.stack
          : undefined,
    filename:
      typeof nested.filename === "string"
        ? nested.filename
        : typeof nested.file === "string"
          ? nested.file
          : typeof nested.id === "string"
            ? nested.id
            : typeof record.id === "string"
              ? record.id
              : undefined,
  };
}

function readViteConsoleError(
  first: unknown,
  second: unknown,
): { message: string; stack?: string; filename?: string } | undefined {
  if (first === "[vite]") return readViteError(second);
  if (typeof first !== "string" || !first.startsWith("[vite]")) {
    return undefined;
  }

  const detail = readViteError(second);
  const message = first.replace(/^\[vite\]\s*/, "") || detail?.message;
  return message
    ? {
        message,
        stack: detail?.stack,
        filename: detail?.filename,
      }
    : undefined;
}

function readUpdatePaths(payload: unknown): string[] {
  const updates =
    typeof payload === "object" &&
    payload !== null &&
    Array.isArray((payload as { updates?: unknown }).updates)
      ? (payload as { updates: Array<Record<string, unknown>> }).updates
      : [];
  const paths = new Set<string>();
  const collectPath = (value: unknown): void => {
    if (typeof value === "string") paths.add(value);
  };
  for (const update of updates) {
    collectPath(update.path);
    collectPath(update.acceptedPath);
    collectPath(update.id);
  }
  return [...paths];
}

async function verifyModuleStillExists(path: string): Promise<boolean> {
  if (typeof fetch !== "function") return true;
  try {
    const response = await fetch(path, { cache: "no-store" });
    const contentType = response.headers.get("content-type") || "";
    return !contentType.includes("text/html");
  } catch {
    return true;
  }
}

function mergeCurrentProblemSnapshots(
  primary: CanvasHostCurrentFrameProblemSnapshot,
  fallback: CanvasHostCurrentFrameProblemSnapshot | null,
): CanvasHostCurrentFrameProblemSnapshot {
  if (!fallback) return primary;
  const currentRenderFailures = [...primary.currentRenderFailures];
  const seen = new Set(
    currentRenderFailures.map(
      (entry) =>
        `${entry.renderId ?? ""}:${entry.failure.sourceKind}:${entry.failure.message}`,
    ),
  );
  for (const entry of fallback.currentRenderFailures) {
    const key = `${entry.renderId ?? ""}:${entry.failure.sourceKind}:${entry.failure.message}`;
    if (seen.has(key)) continue;
    seen.add(key);
    currentRenderFailures.push(entry);
  }
  const currentCanvasFailures = [...(primary.currentCanvasFailures ?? [])];
  const seenCanvas = new Set(
    currentCanvasFailures.map(
      (entry) => `${entry.canvasPath}:${entry.failure.sourceKind}:${entry.failure.message}`,
    ),
  );
  for (const entry of fallback.currentCanvasFailures ?? []) {
    const key = `${entry.canvasPath}:${entry.failure.sourceKind}:${entry.failure.message}`;
    if (seenCanvas.has(key)) continue;
    seenCanvas.add(key);
    currentCanvasFailures.push(entry);
  }
  return {
    currentHostFailure:
      primary.currentHostFailure ?? fallback.currentHostFailure,
    currentRenderFailures,
    currentCanvasFailures,
    observedAt: Math.max(primary.observedAt, fallback.observedAt),
  };
}
