import {
  Component,
  Suspense,
  useEffect,
  useRef,
  type ComponentType,
  type ErrorInfo,
  type ReactNode,
} from "react";

import type { TempoStoryboard } from "../page";
import { useCanvasIdentity, useCanvasStoryboardRenderId } from "./canvas";
import {
  syncStoryboardPortals,
  trackStoryboardPortals,
} from "./portal-tracking";
import {
  useStoryboardErrorReporter,
  useStoryboardPlacement,
  useStoryboardRendered,
  useStoryboardSize,
  useStoryboardStatus,
} from "./runtime-context";

export interface StoryboardLayout {
  x: number;
  y: number;
  width: number;
  height: number;
  zIndex?: number;
  intrinsicSizing?: "root-element";
}

export function Storyboard<Props extends object = object>({
  id,
  name,
  component,
  layout,
  props,
}: {
  id: string;
  component: ComponentType<Props>;
  layout: StoryboardLayout;
  name?: string;
  props?: Props;
}) {
  const Component = component as ComponentType<Props>;

  return (
    <StoryboardSlot id={id} name={name} layout={layout} kind="component">
      <Component {...(props ?? ({} as Props))} />
    </StoryboardSlot>
  );
}

export function LegacyStoryboardV1({
  id,
  storyboard,
}: {
  id: string;
  storyboard: TempoStoryboard;
}) {
  return (
    <StoryboardSlot
      id={id}
      name={storyboard.name}
      layout={storyboard.layout}
      kind="component"
    >
      <LegacyStoryboardV1Render render={storyboard.render} />
    </StoryboardSlot>
  );
}

function LegacyStoryboardV1Render({
  render,
}: {
  render: TempoStoryboard["render"];
}) {
  return <>{render()}</>;
}

export function RouteStoryboard({
  id,
  name,
  route,
  layout,
}: {
  id: string;
  route: string;
  layout: StoryboardLayout;
  name?: string;
}) {
  return (
    <StoryboardSlot
      id={id}
      name={name}
      layout={layout}
      kind="route"
      route={route}
    />
  );
}

export function HtmlStoryboard({
  id,
  name,
  filepath,
  src,
  layout,
}: {
  id: string;
  layout: StoryboardLayout;
  filepath?: string;
  src?: string;
  name?: string;
}) {
  return (
    <StoryboardSlot
      id={id}
      name={name}
      layout={layout}
      kind="html"
      filepath={filepath}
      src={src}
    />
  );
}

export function StoryboardSlot({
  children,
  id,
  kind,
  layout,
  name,
  route,
  filepath,
  src,
}: {
  children?: ReactNode;
  id: string;
  kind: "component" | "route" | "html";
  layout: StoryboardLayout;
  name?: string;
  route?: string;
  filepath?: string;
  src?: string;
}) {
  const renderId = useCanvasStoryboardRenderId(id);
  const canvas = useCanvasIdentity();
  const status = useStoryboardStatus(id);
  const renderSize = useStoryboardSize(id);
  const placement = useStoryboardPlacement(id);
  const markRendered = useStoryboardRendered(id);
  const { reportError, clearError } = useStoryboardErrorReporter(id);
  const renderWidth = renderSize?.width;
  const renderHeight = renderSize?.height;
  const intrinsicSize =
    renderSize?.intrinsicSize ??
    (kind === "component" && layout.intrinsicSizing === "root-element");
  const resetKey = `${renderId}:${renderSize?.revision ?? 0}`;
  const contentRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    if (!contentRef.current || status === "unmounted") return;
    return trackStoryboardPortals(renderId, contentRef.current, status);
  }, [renderId, status]);

  useEffect(() => {
    if (status === "unmounted") return;
    syncStoryboardPortals(renderId, status);
  }, [renderId, status]);

  if (status === "unmounted") return null;

  return (
    <div
      data-render-id={renderId}
      data-render-status={status}
      data-tempo-storyboard-render-id={renderId}
      data-tempo-storyboard-id={id}
      data-tempo-canvas-path={canvas?.path}
      data-tempo-storyboard-name={name}
      data-tempo-storyboard-kind={kind}
      data-tempo-storyboard-route={route}
      data-tempo-storyboard-filepath={filepath}
      data-tempo-storyboard-src={src}
      style={{
        position: "absolute",
        left: placement?.left ?? layout.x,
        top: placement?.top ?? layout.y,
        width: intrinsicSize ? "max-content" : (renderWidth ?? layout.width),
        height: intrinsicSize ? "max-content" : (renderHeight ?? layout.height),
        minWidth: intrinsicSize ? renderWidth : undefined,
        minHeight: intrinsicSize ? renderHeight : undefined,
        zIndex: layout.zIndex,
        visibility: status === "active" ? "visible" : "hidden",
        pointerEvents: status === "active" ? "auto" : "none",
      }}
    >
      <div
        data-render-content={renderId}
        ref={contentRef}
        style={{ width: "100%", height: "100%" }}
      >
        <StoryboardErrorBoundary
          onError={reportError}
          onRecover={clearError}
          resetKey={resetKey}
        >
          <Suspense fallback={null}>
            {children}
            <StoryboardReadySentinel
              active={status === "active"}
              clearError={clearError}
              markRendered={markRendered}
            />
          </Suspense>
        </StoryboardErrorBoundary>
      </div>
    </div>
  );
}

type StoryboardErrorBoundaryProps = {
  children?: ReactNode;
  onError(error: {
    message: string;
    stack?: string;
    componentStack?: string;
  }): void;
  onRecover(): void;
  resetKey: string;
};

type StoryboardErrorBoundaryState = {
  error: Error | null;
  componentStack?: string;
  resetKey: string;
};

const renderErrorRetryDelayMs = 1_000;

class StoryboardErrorBoundary extends Component<
  StoryboardErrorBoundaryProps,
  StoryboardErrorBoundaryState
> {
  private retryTimer: ReturnType<typeof setTimeout> | null = null;

  state: StoryboardErrorBoundaryState = {
    error: null,
    componentStack: undefined,
    resetKey: this.props.resetKey,
  };

  static getDerivedStateFromError(error: Error) {
    return { error };
  }

  static getDerivedStateFromProps(
    props: StoryboardErrorBoundaryProps,
    state: StoryboardErrorBoundaryState,
  ) {
    if (props.resetKey !== state.resetKey) {
      return { error: null, componentStack: undefined, resetKey: props.resetKey };
    }
    return null;
  }

  componentDidCatch(error: Error, info: ErrorInfo) {
    this.setState({ componentStack: info.componentStack ?? undefined });
    this.props.onError({
      message: error.message,
      stack: error.stack,
      componentStack: info.componentStack ?? undefined,
    });
    this.scheduleRetry();
  }

  componentDidUpdate(
    _prevProps: Readonly<StoryboardErrorBoundaryProps>,
    prevState: Readonly<StoryboardErrorBoundaryState>,
  ) {
    if (this.state.error) {
      if (!this.retryTimer) this.scheduleRetry();
      return;
    }
    this.clearRetryTimer();
    if (prevState.error && !this.state.error) {
      this.props.onRecover();
    }
  }

  componentWillUnmount() {
    this.clearRetryTimer();
  }

  private scheduleRetry() {
    this.clearRetryTimer();
    this.retryTimer = setTimeout(() => {
      this.retryTimer = null;
      this.setState((state) =>
        state.error
          ? { error: null, componentStack: undefined, resetKey: state.resetKey }
          : null,
      );
    }, renderErrorRetryDelayMs);
  }

  private clearRetryTimer() {
    if (!this.retryTimer) return;
    clearTimeout(this.retryTimer);
    this.retryTimer = null;
  }

  render() {
    if (this.state.error) {
      return (
        <div
          data-render-error="true"
          data-render-error-message={this.state.error.message}
          style={{ width: "100%", height: "100%" }}
        />
      );
    }
    return this.props.children;
  }
}

function StoryboardReadySentinel({
  active,
  clearError,
  markRendered,
}: {
  active: boolean;
  clearError(): void;
  markRendered(): void;
}) {
  useEffect(() => {
    if (!active) return;
    let paintFrame = 0;
    const commitFrame = requestAnimationFrame(() => {
      paintFrame = requestAnimationFrame(() => {
        clearError();
        markRendered();
      });
    });
    return () => {
      cancelAnimationFrame(commitFrame);
      cancelAnimationFrame(paintFrame);
    };
  }, [active, clearError, markRendered]);

  return null;
}
