import { getCanvasStoryboardRenderId } from "./canvas";

export type CanvasHostCommand = {
  type: string;
  requestId?: unknown;
  payload: Record<string, unknown>;
};

export type CanvasHostRenderTarget = {
  renderId: string;
  canvasPath?: string;
  storyboardId?: string;
};

export type CanvasHostRenderRequest = CanvasHostRenderTarget & {
  importPath: string;
  importName: string;
  props?: Record<string, unknown>;
  width?: number;
  height?: number;
  intrinsicSize?: boolean;
};

export function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null && !Array.isArray(value);
}

export function readCanvasHostCommand(message: unknown): CanvasHostCommand | null {
  if (!isRecord(message) || typeof message.type !== "string") return null;
  return {
    type: message.type,
    requestId: message.requestId,
    payload: isRecord(message.payload) ? message.payload : {},
  };
}

const readTrimmedString = (value: unknown): string | undefined => {
  if (typeof value !== "string") return undefined;
  const normalized = value.trim();
  return normalized.length > 0 ? normalized : undefined;
};

export function resolveRenderTarget(
  payload: Record<string, unknown>,
): CanvasHostRenderTarget | null {
  const explicitRenderId = readTrimmedString(payload.renderId);
  const canvasPath = readTrimmedString(payload.canvasPath);
  const storyboardId = readTrimmedString(payload.storyboardId);
  const renderId =
    explicitRenderId ||
    (canvasPath && storyboardId
      ? getCanvasStoryboardRenderId(canvasPath, storyboardId)
      : storyboardId);

  return renderId
    ? {
        renderId,
        ...(canvasPath ? { canvasPath } : {}),
        ...(storyboardId ? { storyboardId } : {}),
      }
    : null;
}

export function requireRenderTarget(
  commandType: string,
  payload: Record<string, unknown>,
): CanvasHostRenderTarget {
  const target = resolveRenderTarget(payload);
  if (!target) {
    throw new Error(
      `${commandType} requires payload.renderId or payload.canvasPath + payload.storyboardId`,
    );
  }
  return target;
}

const readPositiveFiniteNumber = (
  value: unknown,
  fieldName: string,
): number => {
  if (typeof value !== "number" || !Number.isFinite(value) || value <= 0) {
    throw new Error(`${fieldName} must be a positive finite number`);
  }
  return value;
};

export function readOptionalNumber(
  payload: Record<string, unknown>,
  fieldName: string,
): number | undefined {
  return typeof payload[fieldName] === "number"
    ? (payload[fieldName] as number)
    : undefined;
}

function readOptionalSize(
  payload: Record<string, unknown>,
): { width?: number; height?: number } {
  const hasWidth = payload.width != null;
  const hasHeight = payload.height != null;
  if (!hasWidth && !hasHeight) return {};
  if (!hasWidth || !hasHeight) {
    throw new Error("width and height must be provided together");
  }
  return {
    width: readPositiveFiniteNumber(payload.width, "width"),
    height: readPositiveFiniteNumber(payload.height, "height"),
  };
}

export function readRenderRequest(
  commandType: string,
  payload: Record<string, unknown>,
): CanvasHostRenderRequest {
  const target = requireRenderTarget(commandType, payload);
  const importPath = readTrimmedString(payload.importPath);
  const importName = readTrimmedString(payload.importName);
  const props = isRecord(payload.props) ? payload.props : undefined;

  return {
    ...target,
    importPath: importPath ?? target.canvasPath ?? target.renderId,
    importName: importName ?? target.storyboardId ?? target.renderId,
    ...(props ? { props } : {}),
    ...readOptionalSize(payload),
    intrinsicSize: payload.intrinsicSize === true ? true : undefined,
  };
}

export function readWatchId(
  commandType: string,
  payload: Record<string, unknown>,
): string {
  const watchId = readTrimmedString(payload.watchId);
  if (!watchId) {
    throw new Error(`${commandType} requires payload.watchId`);
  }
  return watchId;
}
