import { useCallback, useEffect, useMemo, useRef, useState } from "react";

import {
  buildRenderContentSelector,
  captureStoryboardCombined,
  captureStoryboardHtml,
  captureStoryboardImage,
  captureStoryboardStaticHtml,
  watchStoryboardCombined,
  watchStoryboardHtml,
} from "./canvas-host-operations";
import type { CanvasHostWatch } from "./canvas-host-runtime";
import type { CanvasHostRuntimeError } from "./runtime-context";
import {
  readCanvasHostCommand,
  readOptionalNumber,
  readRenderRequest,
  readWatchId,
  requireRenderTarget,
  resolveRenderTarget,
} from "./canvas-host-protocol";
import type { CanvasHostRenderRequest } from "./canvas-host-protocol";
import {
  acquireRender,
  buildRenderSizeMap,
  buildRenderStatePayload,
  buildRenderStatusMap,
  evictCachedRenders,
  releaseRender,
  renderRequestMatchesEntry,
  type CanvasHostRenderEntry,
} from "./canvas-host-render-state";
import {
  createCanvasHostProblemTracker,
  installCanvasHostRuntimeProblemTracking,
} from "./runtime-problems";

type WatchLease = {
  renderId: string;
  bindingKey: string;
  watch: CanvasHostWatch;
};

type WatchRequest = {
  commandType: "render-pool:watch-html" | "render-pool:watch-combined";
  requestId: unknown;
  watchId: string;
  source?: MessageEventSource | null;
  targetOrigin?: string;
  request: CanvasHostRenderRequest;
  payload: Record<string, unknown>;
  paused: boolean;
  bindingKey: string;
};

type PendingRenderAck = {
  resolve(): void;
  reject(error: Error): void;
};

type ProblemWatcher = {
  requestId: unknown;
  watchId?: string;
  source?: MessageEventSource | null;
  targetOrigin?: string;
};

// Security boundary: CanvasHost runs inside Tempo's generated host page and is
// driven only by the trusted Electron/frame-pool bridge or by same-page test
// commands (`__render-pool:command`). Browser `message` replies use the
// captured `event.origin`; Electron/file/custom-event commands fall back to
// "*" because those bridges do not provide a stable browser-origin string.
// Command payloads are still structurally validated before use, and replies
// are sent only to the captured source.
function postToMessageSource(
  source: MessageEventSource | null | undefined,
  response: Record<string, unknown>,
  targetOrigin?: string,
): void {
  const origin = safePostMessageTargetOrigin(targetOrigin);
  if (source && "postMessage" in source && source !== window) {
    (source as Window).postMessage(response, origin);
  } else {
    window.postMessage(response, origin);
  }
}

function safePostMessageTargetOrigin(targetOrigin: string | undefined): string {
  if (targetOrigin && targetOrigin !== "null" && targetOrigin !== "file://") {
    return targetOrigin;
  }
  const currentOrigin = window.location.origin;
  return currentOrigin && currentOrigin !== "null" ? currentOrigin : "*";
}

export function useCanvasHostPostMessage(): {
  renderStatusById: ReadonlyMap<string, "active" | "cached">;
  renderSizeById: ReadonlyMap<
    string,
    { width?: number; height?: number; intrinsicSize?: boolean; revision?: number }
  >;
  markStoryboardRendered(storyboardId: string): void;
  reportStoryboardError(storyboardId: string, error: CanvasHostRuntimeError): void;
  clearStoryboardError(storyboardId: string): void;
} {
  const [renderEntriesById, setRenderEntriesById] = useState(
    () => new Map<string, CanvasHostRenderEntry>(),
  );
  const [watchRequestsById, setWatchRequestsById] = useState(
    () => new Map<string, WatchRequest>(),
  );
  const [renderCommitVersionById, setRenderCommitVersionById] = useState(
    () => new Map<string, number>(),
  );
  const renderEntriesRef = useRef(renderEntriesById);
  const watchRequestsRef = useRef(watchRequestsById);
  const maxCachedRef = useRef(20);
  const renderedRenderIdsRef = useRef(new Set<string>());
  const pendingRenderAcksRef = useRef(new Map<string, PendingRenderAck[]>());
  const watchesRef = useRef(new Map<string, WatchLease>());
  const problemWatchersRef = useRef(new Map<string, ProblemWatcher>());
  const problemTrackerRef = useRef(createCanvasHostProblemTracker());
  const renderCommitTimesRef = useRef(new Map<string, number>());
  const sourceAnnotatedCommitTimesRef = useRef(new Map<string, number>());

  const buildProblemSnapshot = useCallback(
    () => problemTrackerRef.current.snapshot(),
    [],
  );

  const recordSourceAnnotatedCommit = useCallback(
    (renderId: string, observedAt = Date.now()) => {
      if (renderSlotHasSourceAnnotations(renderId)) {
        sourceAnnotatedCommitTimesRef.current.set(renderId, observedAt);
      }
    },
    [],
  );

  const publishProblemSnapshot = useCallback(() => {
    const payload = buildProblemSnapshot();
    for (const watcher of problemWatchersRef.current.values()) {
      postToMessageSource(
        watcher.source,
        {
          type: "render-pool:problem-snapshot",
          requestId: watcher.requestId,
          watchId: watcher.watchId,
          payload,
        },
        watcher.targetOrigin,
      );
    }
  }, [buildProblemSnapshot]);

  const setEntries = useCallback(
    (
      update: (
        entries: ReadonlyMap<string, CanvasHostRenderEntry>,
      ) => Map<string, CanvasHostRenderEntry>,
    ) => {
      setRenderEntriesById((entries) => {
        const next = update(entries);
        renderEntriesRef.current = next;
        for (const renderId of [...renderedRenderIdsRef.current]) {
          if (!next.has(renderId)) {
            renderedRenderIdsRef.current.delete(renderId);
            renderCommitTimesRef.current.delete(renderId);
            sourceAnnotatedCommitTimesRef.current.delete(renderId);
          }
        }
        return next;
      });
    },
    [],
  );

  const waitForRender = useCallback(
    (request: CanvasHostRenderRequest): Promise<void> => {
      const current = renderEntriesRef.current.get(request.renderId);
      const alreadyRendered =
        current?.status === "active" &&
        renderedRenderIdsRef.current.has(request.renderId) &&
        renderRequestMatchesEntry(current, request);

      setEntries((entries) => acquireRender(entries, request));

      if (alreadyRendered) {
        return Promise.resolve();
      }

      return new Promise<void>((resolve, reject) => {
        const pendingAcks =
          pendingRenderAcksRef.current.get(request.renderId) ?? [];
        pendingAcks.push({ resolve, reject });
        pendingRenderAcksRef.current.set(request.renderId, pendingAcks);
      });
    },
    [setEntries],
  );

  const releaseRenderLease = useCallback(
    (renderId: string) => {
      setEntries((entries) =>
        releaseRender(entries, renderId, maxCachedRef.current),
      );
    },
    [setEntries],
  );

  const stopRuntimeWatch = useCallback(async (watchId: string) => {
    const existingWatch = watchesRef.current.get(watchId);
    if (!existingWatch) return;
    watchesRef.current.delete(watchId);
    await existingWatch.watch.stop();
  }, []);

  const removeWatchRequest = useCallback(
    async (watchId: string): Promise<void> => {
      const existingRequest = watchRequestsRef.current.get(watchId);
      try {
        await stopRuntimeWatch(watchId);
      } finally {
        if (!existingRequest) return;
        setWatchRequestsById((requests) => {
          const next = new Map(requests);
          next.delete(watchId);
          watchRequestsRef.current = next;
          return next;
        });
        releaseRenderLease(existingRequest.request.renderId);
      }
    },
    [releaseRenderLease, stopRuntimeWatch],
  );

  const buildState = useCallback(
    () => buildRenderStatePayload(renderEntriesRef.current, maxCachedRef.current),
    [],
  );

  const buildHealthSnapshot = useCallback((renderId: string) => {
    const slot = renderId
      ? document.querySelector(buildRenderContentSelector(renderId))
      : null;
    const observedSourceFiles = getObservedSourceFiles(slot);

    return {
      alive: true,
      reactConnected:
        isReactConnected() ||
        renderCommitTimesRef.current.size > 0 ||
        renderEntriesRef.current.size > 0,
      documentReadyState: document.readyState,
      hasViteOverlayElement:
        document.querySelector("vite-error-overlay") !== null,
      lastHostRenderCommitAt: latestTimestamp(renderCommitTimesRef.current),
      lastClaimRenderCommitAt: renderCommitTimesRef.current.get(renderId) ?? null,
      lastHostSourceAnnotatedCommitAt: latestTimestamp(
        sourceAnnotatedCommitTimesRef.current,
      ),
      lastClaimSourceAnnotatedCommitAt:
        sourceAnnotatedCommitTimesRef.current.get(renderId) ?? null,
      renderSlotExists: slot !== null,
      renderSlotHasSourceAnnotatedContent: observedSourceFiles.length > 0,
      renderSlotObservedSourceFiles: observedSourceFiles,
      claimErrorBoundaryTripped:
        problemTrackerRef.current.hasComponentProblem(renderId),
      observedAt: Date.now(),
    };
  }, []);

  const markStoryboardRendered = useCallback(
    (storyboardId: string) => {
      const committedAt = Date.now();
      renderedRenderIdsRef.current.add(storyboardId);
      renderCommitTimesRef.current.set(storyboardId, committedAt);
      recordSourceAnnotatedCommit(storyboardId, committedAt);
      setRenderCommitVersionById((versions) => {
        const next = new Map(versions);
        next.set(storyboardId, (next.get(storyboardId) ?? 0) + 1);
        return next;
      });
      problemTrackerRef.current.clearRecoveredComponentProblemsAfterRender(
        storyboardId,
      );
      const pendingAcks = pendingRenderAcksRef.current.get(storyboardId);
      if (!pendingAcks) return;
      pendingRenderAcksRef.current.delete(storyboardId);
      for (const ack of pendingAcks) {
        ack.resolve();
      }
    },
    [recordSourceAnnotatedCommit],
  );

  const reportStoryboardError = useCallback(
    (storyboardId: string, error: CanvasHostRuntimeError) => {
      renderedRenderIdsRef.current.delete(storyboardId);
      problemTrackerRef.current.reportComponentProblem(
        storyboardId,
        "render-error-boundary",
        error.message,
        {
          stack: error.stack,
          componentStack: error.componentStack,
        },
      );
      const pendingAcks = pendingRenderAcksRef.current.get(storyboardId);
      if (pendingAcks) {
        pendingRenderAcksRef.current.delete(storyboardId);
        const renderError = new Error(error.message);
        for (const ack of pendingAcks) {
          ack.reject(renderError);
        }
      }
    },
    [],
  );

  const clearStoryboardError = useCallback(
    (storyboardId: string) => {
      problemTrackerRef.current.clearComponentProblem(storyboardId, [
        "render-error-boundary",
      ]);
    },
    [],
  );

  useEffect(() => {
    if (typeof window === "undefined") return;

    let cancelled = false;
    const activeWatchIds = new Set(watchRequestsById.keys());

    for (const watchId of watchesRef.current.keys()) {
      if (!activeWatchIds.has(watchId)) {
        void stopRuntimeWatch(watchId);
      }
    }

    for (const request of watchRequestsById.values()) {
      const renderEntry = renderEntriesById.get(request.request.renderId);
      const renderReady =
        renderEntry?.status === "active" &&
        renderedRenderIdsRef.current.has(request.request.renderId) &&
        renderRequestMatchesEntry(renderEntry, request.request);
      if (!renderReady) continue;

      const existing = watchesRef.current.get(request.watchId);
      if (existing?.bindingKey === request.bindingKey) continue;

      void (async () => {
        if (existing) {
          await stopRuntimeWatch(request.watchId);
        }
        if (cancelled) return;

        const onUpdate = (capture: unknown) => {
          recordSourceAnnotatedCommit(request.request.renderId);
          postToMessageSource(
            request.source,
            {
              type: "render-pool:watch-update",
              requestId: request.requestId,
              watchId: request.watchId,
              command: request.commandType,
              payload: { capture },
            },
            request.targetOrigin,
          );
        };
        const onError = (error: Error) => {
          postToMessageSource(
            request.source,
            {
              type: "render-pool:error",
              requestId: request.requestId,
              watchId: request.watchId,
              command: request.commandType,
              error: error.message,
            },
            request.targetOrigin,
          );
        };
        const common = {
          onUpdate,
          onError,
          debounceDelay: readOptionalNumber(request.payload, "debounceDelay"),
          maxWait: readOptionalNumber(request.payload, "maxWait"),
          timeout: readOptionalNumber(request.payload, "timeout"),
        };
        const watch =
          request.commandType === "render-pool:watch-html"
            ? await watchStoryboardHtml(request.request.renderId, common)
            : await watchStoryboardCombined(request.request.renderId, {
                ...common,
                fiberSelector:
                  typeof request.payload.fiberSelector === "string"
                    ? request.payload.fiberSelector
                    : undefined,
                fiberTags: Array.isArray(request.payload.fiberTags)
                  ? request.payload.fiberTags
                  : undefined,
                knownSourceVersion:
                  typeof request.payload.knownSourceVersion === "object" &&
                  request.payload.knownSourceVersion !== null
                    ? request.payload.knownSourceVersion
                    : undefined,
              });

        if (cancelled || !watchRequestsRef.current.has(request.watchId)) {
          await watch.stop();
          return;
        }

        watchesRef.current.set(request.watchId, {
          renderId: request.request.renderId,
          bindingKey: request.bindingKey,
          watch,
        });
        if (request.paused) {
          if (watch.setPaused) watch.setPaused(true);
          else watch.pause?.();
        }
      })().catch((caught: unknown) => {
        postToMessageSource(
          request.source,
          {
            type: "render-pool:error",
            requestId: request.requestId,
            watchId: request.watchId,
            command: request.commandType,
            error: caught instanceof Error ? caught.message : String(caught),
          },
          request.targetOrigin,
        );
      });
    }

    return () => {
      cancelled = true;
    };
  }, [
    recordSourceAnnotatedCommit,
    renderCommitVersionById,
    renderEntriesById,
    stopRuntimeWatch,
    watchRequestsById,
  ]);

  useEffect(() => {
    if (typeof window === "undefined") return;

    const waitForRenderLease = async (
      request: CanvasHostRenderRequest,
    ): Promise<void> => {
      try {
        await waitForRender(request);
      } catch (caught) {
        releaseRenderLease(request.renderId);
        throw caught;
      }
    };

    const withRenderLease = async <Result,>(
      request: CanvasHostRenderRequest,
      run: () => Promise<Result>,
    ): Promise<Result> => {
      await waitForRenderLease(request);
      try {
        return await run();
      } finally {
        releaseRenderLease(request.renderId);
      }
    };

    const handleCommand = (
      message: unknown,
      source?: MessageEventSource | null,
      targetOrigin?: string,
    ) => {
      const command = readCanvasHostCommand(message);
      if (!command) return;
      const payload = command.payload;

      const post = (response: Record<string, unknown>) =>
        postToMessageSource(source, response, targetOrigin);
      const ack = () =>
        post({
          type: "render-pool:ack",
          requestId: command.requestId,
          command: command.type,
        });
      const error = (message: string) =>
        post({
          type: "render-pool:error",
          requestId: command.requestId,
          command: command.type,
          error: message,
        });
      const postAsyncError = (caught: unknown) => {
        error(caught instanceof Error ? caught.message : String(caught));
      };
      const postCaptureResult = (capture: unknown) =>
        post({
          type: "render-pool:capture-result",
          requestId: command.requestId,
          command: command.type,
          payload: { capture },
        });

      try {
        if (command.type === "render-pool:render") {
          const request = readRenderRequest(command.type, payload);
          void waitForRenderLease(request).then(ack).catch(postAsyncError);
          return;
        }

        if (command.type === "render-pool:capture-image") {
          const request = readRenderRequest(command.type, payload);
          void withRenderLease(request, () =>
            captureStoryboardImage(request.renderId, {
              overlaySelector:
                typeof payload.overlaySelector === "string"
                  ? payload.overlaySelector
                  : undefined,
              format:
                payload.format === "jpeg" || payload.format === "png"
                  ? payload.format
                  : undefined,
              quality: readOptionalNumber(payload, "quality"),
              scale: readOptionalNumber(payload, "scale"),
              outputPath:
                typeof payload.outputPath === "string"
                  ? payload.outputPath
                  : undefined,
              forceRefresh: payload.forceRefresh === true,
              portalSelectors: Array.isArray(payload.portalSelectors)
                ? payload.portalSelectors.filter(
                    (selector): selector is string =>
                      typeof selector === "string",
                  )
                : undefined,
            }),
          )
            .then((capture) => {
              recordSourceAnnotatedCommit(request.renderId);
              postCaptureResult(capture);
            })
            .catch(postAsyncError);
          return;
        }

        if (command.type === "render-pool:capture-html") {
          const request = readRenderRequest(command.type, payload);
          void withRenderLease(request, () =>
            captureStoryboardHtml(request.renderId, {
              timeout: readOptionalNumber(payload, "timeout"),
            }),
          )
            .then((capture) => {
              recordSourceAnnotatedCommit(request.renderId);
              postCaptureResult(capture);
            })
            .catch(postAsyncError);
          return;
        }

        if (command.type === "render-pool:capture-static-html") {
          const request = readRenderRequest(command.type, payload);
          void withRenderLease(request, () =>
            captureStoryboardStaticHtml(request.renderId, {
              timeout: readOptionalNumber(payload, "timeout"),
            }),
          )
            .then((capture) => {
              recordSourceAnnotatedCommit(request.renderId);
              postCaptureResult(capture);
            })
            .catch(postAsyncError);
          return;
        }

        if (command.type === "render-pool:capture-combined") {
          const request = readRenderRequest(command.type, payload);
          void withRenderLease(request, () =>
            captureStoryboardCombined(request.renderId, {
              fiberSelector:
                typeof payload.fiberSelector === "string"
                  ? payload.fiberSelector
                  : undefined,
              fiberTags: Array.isArray(payload.fiberTags)
                ? payload.fiberTags
                : undefined,
              timeout: readOptionalNumber(payload, "timeout"),
            }),
          )
            .then((capture) => {
              recordSourceAnnotatedCommit(request.renderId);
              postCaptureResult(capture);
            })
            .catch(postAsyncError);
          return;
        }

        if (
          command.type === "render-pool:watch-html" ||
          command.type === "render-pool:watch-combined"
        ) {
          const request = readRenderRequest(command.type, payload);
          const watchId = readWatchId(command.type, payload);
          void removeWatchRequest(watchId)
            .then(() => {
              setEntries((entries) => acquireRender(entries, request));
              setWatchRequestsById((requests) => {
                const next = new Map(requests);
                next.set(watchId, {
                  commandType: command.type,
                  requestId: command.requestId,
                  watchId,
                  source,
                  targetOrigin,
                  request,
                  payload,
                  paused: false,
                  bindingKey: buildWatchBindingKey(command.type, payload),
                });
                watchRequestsRef.current = next;
                return next;
              });
              ack();
            })
            .catch(postAsyncError);
          return;
        }

        if (command.type === "render-pool:unwatch") {
          const watchId = readWatchId(command.type, payload);
          void removeWatchRequest(watchId).then(ack).catch(postAsyncError);
          return;
        }

        if (command.type === "render-pool:set-watch-paused") {
          const watchId = readWatchId(command.type, payload);
          const paused = payload.paused === true;
          const watch = watchesRef.current.get(watchId)?.watch;
          watch?.setPaused?.(paused);
          if (!watch?.setPaused) {
            if (paused) watch?.pause?.();
            else watch?.resume?.();
          }
          setWatchRequestsById((requests) => {
            const current = requests.get(watchId);
            if (!current || current.paused === paused) return requests;
            const next = new Map(requests);
            next.set(watchId, { ...current, paused });
            watchRequestsRef.current = next;
            return next;
          });
          ack();
          return;
        }

        if (command.type === "render-pool:unrender") {
          const target = requireRenderTarget(command.type, payload);
          releaseRenderLease(target.renderId);
          ack();
          return;
        }

        if (command.type === "render-pool:list") {
          post({
            type: "render-pool:state",
            requestId: command.requestId,
            payload: buildState(),
          });
          return;
        }

        if (command.type === "render-pool:set-cache-limit") {
          const maxCached =
            typeof payload.maxCached === "number" &&
            Number.isInteger(payload.maxCached)
              ? Math.max(0, payload.maxCached)
              : maxCachedRef.current;
          maxCachedRef.current = maxCached;
          setEntries((entries) => evictCachedRenders(entries, maxCached));
          ack();
          return;
        }

        if (command.type === "render-pool:isolate") {
          const target = resolveRenderTarget(payload);
          document.querySelector("[data-render-isolation]")?.remove();

          if (target?.renderId) {
            const style = document.createElement("style");
            style.setAttribute("data-render-isolation", "");
            const escapedId =
              typeof CSS !== "undefined" && typeof CSS.escape === "function"
                ? CSS.escape(target.renderId)
                : target.renderId;
            style.textContent =
              '[data-render-id]:not([data-render-id="' +
              escapedId +
              '"]) { opacity: 0 !important; pointer-events: none !important; }';
            document.head.appendChild(style);
          }
          ack();
          return;
        }

        if (command.type === "render-pool:query-health") {
          const target = resolveRenderTarget(payload);
          post({
            type: "render-pool:health-snapshot",
            requestId: command.requestId,
            snapshot: buildHealthSnapshot(target?.renderId ?? ""),
          });
          return;
        }

        if (command.type === "render-pool:query-problems") {
          post({
            type: "render-pool:problem-snapshot",
            requestId: command.requestId,
            payload: buildProblemSnapshot(),
          });
          return;
        }

        if (command.type === "render-pool:watch-problems") {
          const watchId =
            typeof payload.watchId === "string" && payload.watchId.trim()
              ? payload.watchId
              : String(command.requestId ?? "default");
          problemWatchersRef.current.set(watchId, {
            requestId: command.requestId,
            watchId,
            source,
            targetOrigin,
          });
          ack();
          post({
            type: "render-pool:problem-snapshot",
            requestId: command.requestId,
            watchId,
            payload: buildProblemSnapshot(),
          });
          return;
        }

        if (command.type === "render-pool:unwatch-problems") {
          const watchId =
            typeof payload.watchId === "string" && payload.watchId.trim()
              ? payload.watchId
              : String(command.requestId ?? "default");
          problemWatchersRef.current.delete(watchId);
          ack();
        }
      } catch (caught) {
        postAsyncError(caught);
      }
    };

    const onMessage = (event: MessageEvent) =>
      handleCommand(event.data, event.source, event.origin);
    const onBridgeCommand = (event: Event) =>
      handleCommand(event instanceof CustomEvent ? event.detail : undefined);

    window.addEventListener("message", onMessage);
    window.addEventListener("__render-pool:command", onBridgeCommand);
    const stopProblemPublisher = problemTrackerRef.current.watch(
      publishProblemSnapshot,
    );
    const stopRuntimeProblemTracking = installCanvasHostRuntimeProblemTracking(
      problemTrackerRef.current,
    );
    window.postMessage({ type: "render-pool:ready" }, "*");

    return () => {
      window.removeEventListener("message", onMessage);
      window.removeEventListener("__render-pool:command", onBridgeCommand);
      stopRuntimeProblemTracking();
      stopProblemPublisher();
      for (const { watch } of watchesRef.current.values()) {
        void watch.stop();
      }
      watchesRef.current.clear();
      problemWatchersRef.current.clear();
    };
  }, [
    buildHealthSnapshot,
    buildProblemSnapshot,
    buildState,
    publishProblemSnapshot,
    recordSourceAnnotatedCommit,
    releaseRenderLease,
    removeWatchRequest,
    setEntries,
    waitForRender,
  ]);

  return {
    renderStatusById: useMemo(
      () => buildRenderStatusMap(renderEntriesById),
      [renderEntriesById],
    ),
    renderSizeById: useMemo(
      () => buildRenderSizeMap(renderEntriesById),
      [renderEntriesById],
    ),
    markStoryboardRendered,
    reportStoryboardError,
    clearStoryboardError,
  };
}

function latestTimestamp(values: ReadonlyMap<string, number>): number | null {
  let latest: number | null = null;
  for (const value of values.values()) {
    latest = latest === null ? value : Math.max(latest, value);
  }
  return latest;
}

function isReactConnected(): boolean {
  const hook = (
    window as unknown as {
      __REACT_DEVTOOLS_GLOBAL_HOOK__?: { renderers?: { size?: number } };
    }
  ).__REACT_DEVTOOLS_GLOBAL_HOOK__;
  return (hook?.renderers?.size ?? 0) > 0;
}

function buildWatchBindingKey(commandType: string, payload: Record<string, unknown>): string {
  try {
    return JSON.stringify({ commandType, payload });
  } catch {
    return `${commandType}:${Date.now()}`;
  }
}

const sourceAnnotationSelector =
  "[data-tempo-source-file], [data-tempo-source-loc], [data-tempo-filepath], [data-tempo-html-filepath]";

function renderSlotHasSourceAnnotations(renderId: string): boolean {
  const slot =
    typeof document === "undefined"
      ? null
      : document.querySelector(buildRenderContentSelector(renderId));
  return getObservedSourceFiles(slot).length > 0;
}

function getObservedSourceFiles(slot: Element | null): string[] {
  if (!slot) return [];
  return [
    ...new Set(
      [...slot.querySelectorAll(sourceAnnotationSelector)]
        .flatMap((element) => [
          element.getAttribute("data-tempo-source-file"),
          element.getAttribute("data-tempo-filepath"),
          element.getAttribute("data-tempo-html-filepath"),
          element.getAttribute("data-tempo-source-loc"),
        ])
        .filter((file): file is string => Boolean(file)),
    ),
  ];
}
