import { createContext, useCallback, useContext } from "react";

import { useCanvasStoryboardRenderId } from "./canvas";

export type CanvasHostRuntimeError = {
  message: string;
  stack?: string;
  componentStack?: string;
};

export type CanvasHostRuntimeSize = {
  width?: number | string;
  height?: number | string;
  intrinsicSize?: boolean;
  revision?: number;
};

export type CanvasHostRuntimePlacement = {
  left: number;
  top: number;
};

export type CanvasHostRuntime = {
  getStoryboardStatus(storyboardId: string): "active" | "cached" | "unmounted";
  getStoryboardSize(storyboardId: string): CanvasHostRuntimeSize | undefined;
  getStoryboardPlacement(
    storyboardId: string,
  ): CanvasHostRuntimePlacement | undefined;
  markStoryboardRendered(storyboardId: string): void;
  reportStoryboardError(storyboardId: string, error: CanvasHostRuntimeError): void;
  clearStoryboardError(storyboardId: string): void;
};

export const CanvasHostContext = createContext<CanvasHostRuntime | null>(null);

function useRequiredCanvasHost(): CanvasHostRuntime {
  const host = useContext(CanvasHostContext);
  if (!host) {
    throw new Error(
      "Tempo canvas components must be rendered inside <CanvasHost>.",
    );
  }
  return host;
}

export function useActiveState(storyboardId: string): boolean {
  const renderId = useCanvasStoryboardRenderId(storyboardId);
  const host = useRequiredCanvasHost();
  return host.getStoryboardStatus(renderId) !== "unmounted";
}

export function useStoryboardStatus(
  storyboardId: string,
): "active" | "cached" | "unmounted" {
  const renderId = useCanvasStoryboardRenderId(storyboardId);
  const host = useRequiredCanvasHost();
  return host.getStoryboardStatus(renderId);
}

export function useStoryboardRendered(storyboardId: string): () => void {
  const renderId = useCanvasStoryboardRenderId(storyboardId);
  const host = useRequiredCanvasHost();
  return useCallback(() => {
    host.markStoryboardRendered(renderId);
  }, [host, renderId]);
}

export function useStoryboardErrorReporter(storyboardId: string): {
  reportError(error: CanvasHostRuntimeError): void;
  clearError(): void;
} {
  const renderId = useCanvasStoryboardRenderId(storyboardId);
  const host = useRequiredCanvasHost();
  const reportError = useCallback(
    (error: CanvasHostRuntimeError) => {
      host.reportStoryboardError(renderId, error);
    },
    [host, renderId],
  );
  const clearError = useCallback(() => {
    host.clearStoryboardError(renderId);
  }, [host, renderId]);
  return { reportError, clearError };
}

export function useStoryboardSize(
  storyboardId: string,
): CanvasHostRuntimeSize | undefined {
  const renderId = useCanvasStoryboardRenderId(storyboardId);
  const host = useRequiredCanvasHost();
  return host.getStoryboardSize(renderId);
}

export function useStoryboardPlacement(
  storyboardId: string,
): CanvasHostRuntimePlacement | undefined {
  const renderId = useCanvasStoryboardRenderId(storyboardId);
  const host = useRequiredCanvasHost();
  return host.getStoryboardPlacement(renderId);
}
