type FiberLike = {
  return: FiberLike | null;
  stateNode: unknown;
};

type PortalWatcher = {
  element: Element;
  onPortalFound(portalRoot: Element): void;
  onPortalRemoved(portalRoot: Element): void;
};

type PortalInlineStyleValue = {
  value: string;
  priority: string;
};

type PortalInlineStyle = {
  visibility: PortalInlineStyleValue;
  pointerEvents: PortalInlineStyleValue;
  contentVisibility: PortalInlineStyleValue;
  transition: PortalInlineStyleValue;
  animation: PortalInlineStyleValue;
};

type PortalManagedProperty = {
  // The PortalInlineStyle field that holds this property's saved baseline.
  key: keyof PortalInlineStyle;
  // The CSS property name as written in inline styles.
  cssName: string;
  // The value forced (with !important) while the portal is hidden.
  hiddenValue: string;
};

// Single source of truth for the inline-style properties this module overrides
// to hide cached/inactive portals, so the hide path and the restore path can't
// drift out of sync.
const PORTAL_MANAGED_PROPERTIES: readonly PortalManagedProperty[] = [
  { key: "visibility", cssName: "visibility", hiddenValue: "hidden" },
  { key: "pointerEvents", cssName: "pointer-events", hiddenValue: "none" },
  {
    key: "contentVisibility",
    cssName: "content-visibility",
    hiddenValue: "hidden",
  },
  { key: "transition", cssName: "transition", hiddenValue: "none" },
  { key: "animation", cssName: "animation", hiddenValue: "none" },
];

const portalElementsByRenderId = new Map<string, Set<Element>>();
const portalOwnerRenderIdsByElement = new Map<Element, Set<string>>();
const portalInlineStyleByElement = new Map<Element, PortalInlineStyle>();
const renderStatusById = new Map<string, "active" | "cached">();
const projectionPortalIdAttribute = "data-projection-portal-id";
let nextSdkPortalId = 1;

function escapeAttributeValue(value: string): string {
  return value.replace(/\\/g, "\\\\").replace(/"/g, '\\"');
}

function ensureProjectionPortalId(portalRoot: Element): string {
  const existingId = portalRoot.getAttribute(projectionPortalIdAttribute);
  if (existingId) return existingId;

  const id = `tempo-sdk-portal-${nextSdkPortalId++}`;
  portalRoot.setAttribute(projectionPortalIdAttribute, id);
  return id;
}

function buildProjectionPortalSelector(portalRoot: Element): string {
  return `[${projectionPortalIdAttribute}="${escapeAttributeValue(
    ensureProjectionPortalId(portalRoot),
  )}"]`;
}

function findFiberKey(element: Element): string | null {
  return (
    Object.keys(element).find(
      (key) =>
        key.startsWith("__reactFiber$") ||
        key.startsWith("__reactInternalInstance$"),
    ) ?? null
  );
}

function findContainerKey(element: Element): string | null {
  return Object.keys(element).find((key) => key.startsWith("__reactContainer$")) ?? null;
}

function getFiberFromElement(element: Element): FiberLike | null {
  const fiberKey = findFiberKey(element);
  if (fiberKey) {
    return (
      (element as unknown as Record<string, FiberLike | undefined>)[fiberKey] ??
      null
    );
  }

  const containerKey = findContainerKey(element);
  if (containerKey) {
    return (
      (element as unknown as Record<string, FiberLike | undefined>)[
        containerKey
      ] ?? null
    );
  }

  return null;
}

class PortalTracker {
  private readonly watchers = new Set<PortalWatcher>();
  private readonly ownerWatchersByPortalRoot = new Map<
    Element,
    Set<PortalWatcher>
  >();
  private observer: MutationObserver | null = null;

  register(watcher: PortalWatcher): () => void {
    this.watchers.add(watcher);

    if (this.watchers.size === 1) {
      this.startObserving();
    }

    if (typeof document !== "undefined" && document.body) {
      this.checkExistingElements();
      queueMicrotask(() => this.checkExistingElements());
    }

    return () => this.unregister(watcher);
  }

  private checkExistingElements(): void {
    if (typeof document === "undefined" || !document.body) return;
    for (const child of Array.from(document.body.children)) {
      this.checkElement(child);
    }
  }

  private unregister(watcher: PortalWatcher): void {
    this.watchers.delete(watcher);

    for (const [portalRoot, owners] of this.ownerWatchersByPortalRoot) {
      owners.delete(watcher);
      if (owners.size === 0) {
        this.ownerWatchersByPortalRoot.delete(portalRoot);
      }
    }

    if (this.watchers.size === 0) {
      this.stopObserving();
    }
  }

  private startObserving(): void {
    if (
      this.observer ||
      typeof document === "undefined" ||
      !document.body ||
      typeof MutationObserver === "undefined"
    ) {
      return;
    }

    this.observer = new MutationObserver(this.handleMutations);
    this.observer.observe(document.body, { childList: true });
  }

  private stopObserving(): void {
    this.observer?.disconnect();
    this.observer = null;
  }

  private handleMutations = (mutations: MutationRecord[]): void => {
    for (const mutation of mutations) {
      for (const node of mutation.addedNodes) {
        if (node instanceof Element) {
          queueMicrotask(() => this.checkElement(node));
        }
      }

      for (const node of mutation.removedNodes) {
        if (!(node instanceof Element)) continue;
        const owners = this.ownerWatchersByPortalRoot.get(node);
        if (!owners) continue;
        for (const owner of owners) {
          owner.onPortalRemoved(node);
        }
        this.ownerWatchersByPortalRoot.delete(node);
      }
    }
  };

  private checkElement(element: Element): void {
    const ancestorDomNodes = this.getDomAncestorsViaFiber(element);
    if (ancestorDomNodes.length === 0) return;

    let owners = this.ownerWatchersByPortalRoot.get(element);
    for (const watcher of this.watchers) {
      const belongsToWatcher = ancestorDomNodes.some(
        (node) => watcher.element.contains(node) || watcher.element === node,
      );
      if (!belongsToWatcher) continue;

      if (!owners) {
        owners = new Set<PortalWatcher>();
        this.ownerWatchersByPortalRoot.set(element, owners);
      }
      if (owners.has(watcher)) continue;

      owners.add(watcher);
      watcher.onPortalFound(element);
    }
  }

  private getDomAncestorsViaFiber(element: Element): Element[] {
    const fiber = getFiberFromElement(element);
    if (!fiber) return [];

    const domNodes: Element[] = [];
    let current: FiberLike | null = fiber.return;
    while (current) {
      if (current.stateNode instanceof Element) {
        domNodes.push(current.stateNode);
      }
      current = current.return;
    }
    return domNodes;
  }
}

let portalTracker: PortalTracker | null = null;

function getPortalTracker(): PortalTracker {
  if (!portalTracker) {
    portalTracker = new PortalTracker();
  }
  return portalTracker;
}

function getStylablePortalElement(
  portalRoot: Element,
): HTMLElement | SVGElement | null {
  if (portalRoot instanceof HTMLElement || portalRoot instanceof SVGElement) {
    return portalRoot;
  }
  return null;
}

function ensurePortalInlineStyle(portalRoot: Element): PortalInlineStyle {
  const existing = portalInlineStyleByElement.get(portalRoot);
  if (existing) return existing;

  const stylableElement = getStylablePortalElement(portalRoot);
  const baseline = {
    visibility: readInlineStyleValue(stylableElement, "visibility"),
    pointerEvents: readInlineStyleValue(stylableElement, "pointer-events"),
    contentVisibility: readInlineStyleValue(
      stylableElement,
      "content-visibility",
    ),
    transition: readInlineStyleValue(stylableElement, "transition"),
    animation: readInlineStyleValue(stylableElement, "animation"),
  };
  portalInlineStyleByElement.set(portalRoot, baseline);
  return baseline;
}

function readInlineStyleValue(
  element: HTMLElement | SVGElement | null,
  propertyName: string,
): PortalInlineStyleValue {
  return {
    value: element?.style.getPropertyValue(propertyName) ?? "",
    priority: element?.style.getPropertyPriority(propertyName) ?? "",
  };
}

function restoreInlineStyleValue(
  style: CSSStyleDeclaration,
  propertyName: string,
  baseline: PortalInlineStyleValue,
): void {
  if (baseline.value) {
    style.setProperty(propertyName, baseline.value, baseline.priority);
    return;
  }
  style.removeProperty(propertyName);
}

function restorePortalInlineStyle(portalRoot: Element): void {
  const stylableElement = getStylablePortalElement(portalRoot);
  const baseline = portalInlineStyleByElement.get(portalRoot);
  if (!stylableElement || !baseline) return;

  for (const property of PORTAL_MANAGED_PROPERTIES) {
    restoreInlineStyleValue(
      stylableElement.style,
      property.cssName,
      baseline[property.key],
    );
  }
}

function syncPortalVisibility(portalRoot: Element): void {
  const owners = portalOwnerRenderIdsByElement.get(portalRoot);
  if (!owners || owners.size === 0) {
    restorePortalInlineStyle(portalRoot);
    portalInlineStyleByElement.delete(portalRoot);
    return;
  }

  const stylableElement = getStylablePortalElement(portalRoot);
  if (!stylableElement) return;

  const shouldBeVisible = [...owners].some(
    (renderId) => renderStatusById.get(renderId) === "active",
  );

  if (shouldBeVisible) {
    restorePortalInlineStyle(portalRoot);
    portalInlineStyleByElement.delete(portalRoot);
    return;
  }

  ensurePortalInlineStyle(portalRoot);
  for (const property of PORTAL_MANAGED_PROPERTIES) {
    stylableElement.style.setProperty(
      property.cssName,
      property.hiddenValue,
      "important",
    );
  }
}

function trackPortal(renderId: string, portalRoot: Element): void {
  ensureProjectionPortalId(portalRoot);

  const portals = portalElementsByRenderId.get(renderId) ?? new Set<Element>();
  portals.add(portalRoot);
  portalElementsByRenderId.set(renderId, portals);

  const owners = portalOwnerRenderIdsByElement.get(portalRoot) ?? new Set<string>();
  owners.add(renderId);
  portalOwnerRenderIdsByElement.set(portalRoot, owners);
  syncPortalVisibility(portalRoot);
}

function untrackPortal(renderId: string, portalRoot: Element): void {
  const portals = portalElementsByRenderId.get(renderId);
  if (!portals) return;

  portals.delete(portalRoot);
  if (portals.size === 0) {
    portalElementsByRenderId.delete(renderId);
  }

  const owners = portalOwnerRenderIdsByElement.get(portalRoot);
  if (owners) {
    owners.delete(renderId);
    if (owners.size === 0) {
      portalOwnerRenderIdsByElement.delete(portalRoot);
    }
  }
  syncPortalVisibility(portalRoot);
}

export function releaseStoryboardPortals(renderId: string): void {
  const portals = portalElementsByRenderId.get(renderId);
  if (!portals) {
    renderStatusById.delete(renderId);
    return;
  }

  for (const portalRoot of [...portals]) {
    untrackPortal(renderId, portalRoot);
  }
  renderStatusById.delete(renderId);
}

export function getStoryboardPortalSelectors(renderId: string): string[] {
  const portals = portalElementsByRenderId.get(renderId);
  if (!portals) return [];
  return [...portals]
    .filter((portalRoot) => portalRoot.isConnected)
    .map(buildProjectionPortalSelector);
}

export function syncStoryboardPortals(
  renderId: string,
  status: "active" | "cached",
): void {
  renderStatusById.set(renderId, status);
  const portals = portalElementsByRenderId.get(renderId);
  if (!portals) return;
  for (const portalRoot of portals) {
    syncPortalVisibility(portalRoot);
  }
}

export function trackStoryboardPortals(
  renderId: string,
  element: Element,
  status: "active" | "cached",
): () => void {
  syncStoryboardPortals(renderId, status);
  const unregister = getPortalTracker().register({
    element,
    onPortalFound(portalRoot) {
      trackPortal(renderId, portalRoot);
    },
    onPortalRemoved(portalRoot) {
      untrackPortal(renderId, portalRoot);
    },
  });

  return () => {
    unregister();
    releaseStoryboardPortals(renderId);
  };
}
